import {
  autoinject,
  bindable,
  computedFrom,
  containerless,
} from "aurelia-framework";
import { Job } from "../../models/job";
import { JobStatus } from "../../models/job-status";
import { JobType } from "../../models/job-type";
import { Foreman } from "../../models/foreman";
import { JobService } from "../../services/data/job-service";
import { Notifications } from "../../services/notifications";
import { Authentication, Roles } from "../../services/auth";
import { UserService } from "../../services/data/users-service";

@autoinject
@containerless
export class ListItem {
  @bindable job: Job;
  el: Element;
  expanded: boolean = false;
  foremen: string[];
  salesmen: string[];
  projectManagers: string[];
  jobStatuses: JobStatus[] = JobStatus.OPTIONS;
  canEdit: boolean;

  constructor(
    private jobService: JobService,
    private auth: Authentication,
    userService: UserService
  ) {
    // only office admin can close jobs
    if (!this.auth.isInRole(Roles.OfficeAdmin)) {
      var close = this.jobStatuses.findIndex(
        (status) => status.id === JobStatus.CLOSED
      );
      if (close !== -1) {
        this.jobStatuses.splice(close, 1);
      }
    }

    this.canEdit =
      this.auth.isInRole(Roles.Administrator) ||
      this.auth.isInRole(Roles.EditAllJobs);

    if (this.canEdit) {
      userService
        .getAllInRole(Roles.Foreman)
        .then((foremen) => (this.foremen = foremen.map((f) => f.name)));

      userService
        .getAllInRole(Roles.Foreman)
        .then((salesmen) => (this.salesmen = salesmen.map((s) => s.name)));

      userService
        .getAllInRole(Roles.ProjectManager)
        .then(
          (managers) => (this.projectManagers = managers.map((m) => m.name))
        );
    } else {
      this.foremen = [];
      this.salesmen = [];
      this.projectManagers = [];
    }
  }

  attached() {
    if (!this.canEdit) {
      return;
    }

    $(".dropdown.status", this.el).dropdown({
      onChange: this.onStatusChanged.bind(this),
    });
    $(".dropdown.foreman", this.el).dropdown({
      onChange: this.onForemanChanged.bind(this),
    });
    $(".dropdown.salesman", this.el).dropdown({
      onChange: this.onSalesmanChanged.bind(this),
    });
    $(".dropdown.project-manager", this.el).dropdown({
      onChange: this.onProjectManagerChanged.bind(this),
    });
  }

  detached() {
    if (!this.canEdit) {
      return;
    }

    $(".dropdown.status", this.el).dropdown("destroy");
    $(".dropdown.foreman", this.el).dropdown("destroy");
    $(".dropdown.salesman", this.el).dropdown("destroy");
    $(".dropdown.project-manager", this.el).dropdown("destroy");
  }

  toggleExpanded() {
    this.expanded = !this.expanded;
  }

  @computedFrom("job.salesman")
  get salesmanDisplay(): string {
    return Array.isArray(this.job.salesman)
      ? this.job.salesman.join(", ") || "Unassigned"
      : this.job.salesman || "Unassigned";
  }

  @computedFrom("job.project_manager")
  get projectManagerDisplay(): string {
    return Array.isArray(this.job.project_manager)
      ? this.job.project_manager.join(", ") || "Unassigned"
      : this.job.project_manager || "Unassigned";
  }

  @computedFrom("job.planning_status")
  get planningStatus(): JobStatus {
    return JobStatus.OPTIONS.find((s) => s.id === this.job.planning_status);
  }

  @computedFrom("job.status")
  get jobStatus(): JobStatus {
    return this.jobStatuses.find((s) => s.id == this.job.status);
  }

  @computedFrom("job.foreman")
  get foremanDisplay(): string {
    return Array.isArray(this.job.foreman)
      ? this.job.foreman.join(", ") || "Unassigned"
      : this.job.foreman || "Unassigned";
  }

  @computedFrom("job.foreman")
  get foremanColour(): any {
    const foreman = Array.isArray(this.job.foreman)
        ? "white"
        : (this.job.foreman || "").toLowerCase(),
      bg = Foreman.BackgroundColours[foreman] || "white",
      color = bg === "white" ? "black" : "white";
    return { "background-color": bg, color };
  }

  @computedFrom("job.status")
  get isPending() {
    return this.job.status === "pending";
  }

  @computedFrom("job.status")
  get isInProgress() {
    return this.job.status === JobStatus.PENDING;
  }

  @computedFrom("job.status")
  get isComplete() {
    return this.job.status === JobStatus.COMPLETE;
  }

  @computedFrom("job.status")
  get isClosed(): boolean {
    return this.job.status === JobStatus.CLOSED;
  }

  @computedFrom("job.job_type")
  get isProject() {
    return this.job.job_type === JobType.PROJECT;
  }

  @computedFrom("job.job_type")
  get isServiceCall() {
    return this.job.job_type === JobType.SERVICE_CALL;
  }

  @computedFrom("job.job_type", "job.number")
  get jobNumberDisplay() {
    const prefix =
      this.job.job_type === JobType.SERVICE_CALL
        ? "S"
        : this.job.job_type === JobType.WORK_ORDER
        ? "W"
        : "P";
    return `${prefix}-${this.job.number}`;
  }

  onStatusChanged(value: string) {
    this.job.status = value;

    this.save("Status");
  }

  onForemanChanged(value: string) {
    this.job.foreman = value;
    this.save("Foreman");
  }

  onSalesmanChanged(value: string) {
    this.job.salesman = value;
    this.save("Salesman");
  }

  onProjectManagerChanged(value: string) {
    this.job.project_manager = value;
    this.save("Product Manager");
  }

  save(field: string): Promise<void> {
    return this.jobService
      .save(this.job)
      .then((response) => {
        this.job._rev = response.rev;
        Notifications.success(`${field} updated`);
      })
      .catch(Notifications.error);
  }
}
